{
        struct create_cap_group_args args;
        struct cap_group *cap_group;
        struct vmspace *vmspace;
        cap_t slot_id;

        /* Validate user pointer - ensure it's within user address range */
        if (!is_user_addr((void *)cap_group_args_p))
                return -EINVAL;

        /* Copy arguments from user space to kernel space */
        copy_from_user(&args, (void *)cap_group_args_p, sizeof(args));
